'use client'

import React, {
  createContext,
  useCallback,
  useContext,
  useRef,
  useState,
} from 'react'

type WindowWithAudio = Window & {
  webkitAudioContext?: {
    new (contextOptions?: AudioContextOptions): AudioContext
    prototype: AudioContext
  }
}

type SaunkAudioContextValue = {
  isSfxEnabled: boolean
  isMusicEnabled: boolean
  toggleSfx: () => void
  toggleMusic: () => void
  playHoverSound: () => void
  playClickSound: () => void
  startBackgroundMusic: () => void
}

const SaunkAudioContext = createContext<SaunkAudioContextValue | null>(null)

// caminho dentro de /public
const BG_MUSIC_SRC = '/sounds/void-music.mp3'

export function AudioProvider({ children }: { children: React.ReactNode }) {
  const [isSfxEnabled, setIsSfxEnabled] = useState(true)
  const [isMusicEnabled, setIsMusicEnabled] = useState(true)

  // FX (hover/click)
  const audioCtxRef = useRef<AudioContext | null>(null)

  // música de fundo
  const bgAudioRef = useRef<HTMLAudioElement | null>(null)

  const ensureAudioContext = useCallback(() => {
    if (audioCtxRef.current) return
    if (typeof window === 'undefined') return

    const w = window as WindowWithAudio & typeof window
    const Ctx = w.AudioContext ?? w.webkitAudioContext
    if (!Ctx) return

    audioCtxRef.current = new Ctx()
  }, [])

  const playHoverSound = useCallback(() => {
    if (!isSfxEnabled) return

    ensureAudioContext()
    const ctx = audioCtxRef.current
    if (!ctx) return

    const now = ctx.currentTime
    const osc = ctx.createOscillator()
    const gain = ctx.createGain()

    osc.connect(gain)
    gain.connect(ctx.destination)

    osc.frequency.setValueAtTime(800, now)
    osc.frequency.exponentialRampToValueAtTime(600, now + 0.05)
    gain.gain.setValueAtTime(0.05, now)
    gain.gain.exponentialRampToValueAtTime(0.001, now + 0.08)

    osc.start(now)
    osc.stop(now + 0.08)
  }, [isSfxEnabled, ensureAudioContext])

  const playClickSound = useCallback(() => {
    if (!isSfxEnabled) return

    ensureAudioContext()
    const ctx = audioCtxRef.current
    if (!ctx) return

    const now = ctx.currentTime
    const osc = ctx.createOscillator()
    const gain = ctx.createGain()

    osc.connect(gain)
    gain.connect(ctx.destination)

    osc.frequency.setValueAtTime(1200, now)
    osc.frequency.exponentialRampToValueAtTime(400, now + 0.1)
    gain.gain.setValueAtTime(0.08, now)
    gain.gain.exponentialRampToValueAtTime(0.001, now + 0.12)

    osc.start(now)
    osc.stop(now + 0.12)
  }, [isSfxEnabled, ensureAudioContext])

  const startBackgroundMusic = useCallback(() => {
    if (!isMusicEnabled) return

    let audio = bgAudioRef.current
    if (!audio) {
      audio = new Audio(BG_MUSIC_SRC)
      audio.loop = true
      audio.volume = 0
      bgAudioRef.current = audio
    }

    audio
      .play()
      .then(() => {
        const targetVolume = 0.25
        const step = 0.02

        const interval = setInterval(() => {
          const currentAudio = bgAudioRef.current
          if (!currentAudio || !isMusicEnabled) {
            clearInterval(interval)
            return
          }

          if (currentAudio.volume >= targetVolume) {
            currentAudio.volume = targetVolume
            clearInterval(interval)
          } else {
            currentAudio.volume = Math.min(
              targetVolume,
              currentAudio.volume + step
            )
          }
        }, 200)
      })
      .catch(() => {
        // se o navegador bloquear, o próximo clique destrava
      })
  }, [isMusicEnabled])

  const toggleSfx = useCallback(() => {
    setIsSfxEnabled((prev) => !prev)
  }, [])

  const toggleMusic = useCallback(() => {
    setIsMusicEnabled((prev) => {
      const next = !prev
      const audio = bgAudioRef.current

      if (audio) {
        if (!next) {
          audio.pause()
        } else {
          audio.play().catch(() => {
            // se der erro, próximo clique ajeita
          })
        }
      }

      return next
    })
  }, [])

  const value: SaunkAudioContextValue = {
    isSfxEnabled,
    isMusicEnabled,
    toggleSfx,
    toggleMusic,
    playHoverSound,
    playClickSound,
    startBackgroundMusic,
  }

  return (
    <SaunkAudioContext.Provider value={value}>
      {children}
    </SaunkAudioContext.Provider>
  )
}

export function useAudio() {
  const ctx = useContext(SaunkAudioContext)
  if (!ctx) {
    throw new Error('useAudio deve ser usado dentro de <AudioProvider>')
  }
  return ctx
}
